/* ── Device-specific constants (measured via ./bench_grid profile) ── */

/* PAIRED_CACHED_CORR_RATIO: cost of paired cached correlate / full FFT pipeline.
 * Measured via measure_phase_split(): fwd + 2×(pw+ifft) relative to 2×fwd+pw+ifft.
 * M3 Max: fwd≈0.30, pw≈0.045, ifft≈0.32 → paired = 1.03×calib. */
#ifndef PAIRED_CACHED_CORR_RATIO
#define PAIRED_CACHED_CORR_RATIO 1.03
#endif

/* FMA_NS: nanoseconds per scalar FMA for schoolbook / correction loops.
 * M3 Max (NEON, 2-wide FP64): 0.25 ns/FMA. */
#ifndef FMA_NS
#define FMA_NS 0.25
#endif

/* FFT_OVERHEAD_NS: per-call overhead not captured in calibration
 * (plan lookup, buffer copies, result extraction). Measured via ./bench_grid profile. */
#ifndef FFT_OVERHEAD_NS
#define FFT_OVERHEAD_NS 40.0
#endif

/* INDEP_PAIR_RATIO: cost of correlate_fft_pair (shared g, fresh P FFTs) / full pipeline.
 * = (fwd_g + 2×fwd_P_rev + 2×pw + 2×ifft) / (2×fwd + pw + ifft)
 * M3 Max: (0.30 + 2×0.30 + 2×0.045 + 2×0.32) / 1.0 ≈ 1.63.
 * Original estimate was 1.25; the measured value should be used. */
#ifndef INDEP_PAIR_RATIO
#define INDEP_PAIR_RATIO 1.25
#endif

/* ── Cost model functions ── */

static double best_fft_config_joint(int build_conv, int corr_conv,
                                     int *out_size, int *out_build_m, int *out_corr_m) {
    int max_conv = (build_conv > corr_conv) ? build_conv : corr_conv;
    int min_size = max_conv / 2 + 1;

    int lo = 0, hi = N_CALIBRATED_SIZES - 1;
    int half = min_size;
    while (lo < hi) { int mid = (lo+hi)>>1; if (calib_sizes[mid] < half) lo = mid+1; else hi = mid; }

    double best_cost = 1e18;
    *out_size = 0; *out_build_m = 0; *out_corr_m = 0;

    for (int i = lo; i < N_CALIBRATED_SIZES; i++) {
        int S = calib_sizes[i];
        if (S > 2 * max_conv) break;
        if (S < min_size) continue;
        int mb = (S >= build_conv) ? 0 : build_conv - S;
        int mc = (S >= corr_conv) ? 0 : corr_conv - S;
        double cost = calib_times_ns[i]
                    + (double)(mb+1)*(mb+1) * FMA_NS
                    + calib_times_ns[i] * PAIRED_CACHED_CORR_RATIO
                    + 2.0 * (double)(mc+1)*(mc+1) * FMA_NS;
        if (cost < best_cost) {
            best_cost = cost;
            *out_size = S;
            *out_build_m = mb;
            *out_corr_m = mc;
        }
    }
    return best_cost;
}

/* For a needed convolution length L, find the fastest FFT size.
 * Scans all smooth numbers from L/2 to next_pow2(L). For each candidate S:
 *   if S >= L: m = 0 (no wrapping, standard convolution)
 *   if S < L:  m = L - S (wrap m high-degree coefficients, correction = O(m) FMAs)
 *   cost = fft_time[S] + correction_time(m)
 * Returns the S with minimum cost. No arbitrary m cap — correction is ~3.5ns per m. */
static void best_fft_config(int L, int *out_size, int *out_wrap_m) {
    /* Binary search for starting index: first smooth >= L/2 */
    int lo = 0, hi = N_CALIBRATED_SIZES - 1;
    int half_L = L > 1 ? L / 2 : 1;
    while (lo < hi) { int mid = (lo+hi)>>1; if (calib_sizes[mid] < half_L) lo = mid+1; else hi = mid; }

    double best_cost = 1e18;
    *out_size = 0; *out_wrap_m = 0;

    /* FFT must be >= L to avoid multi-position cyclic aliasing.
     * m-wrap only works when the FFT is exactly L (wrapping the one z^{2d} term)
     * or slightly below L (wrapping a few terms with known correction).
     * But the IFFT output is only fft_n values — positions >= fft_n are
     * inaccessible. So the correction loop can only fix positions 0..wrap_m
     * (the low-index wrapped terms), NOT high-index terms that are simply missing.
     *
     * Therefore: fft_n must be >= L (the full convolution length).
     * The m-wrap saves by using a SMALLER smooth number that's still >= L.
     * Wait — that contradicts the purpose. Let me reconsider.
     *
     * Actually: for m-wrap, fft_n = S where S = L - m. The cyclic convolution
     * of size S wraps terms at positions S..2d to positions 0..(2d-S).
     * The IFFT produces S values: c_cyc[0..S-1]. These contain:
     *   c_cyc[i] = C_true[i] + C_true[i+S]  for i where i+S <= 2d
     *   c_cyc[i] = C_true[i]                 for i where i+S > 2d
     * The correction subtracts C_true[i+S] from c_cyc[i] for i = 0..m (= 2d-S).
     * And C_true[S..2d] (the high terms) are computed separately in the correction.
     * So c[0..S-1] comes from the IFFT, and c[S..2d] comes from the correction.
     * This works! The only constraint: fft_n >= d+1 (to hold the input).
     */
    int min_size = L / 2 + 1;
    for (int i = lo; i < N_CALIBRATED_SIZES; i++) {
        int S = calib_sizes[i];
        if (S > 2 * L) break;  /* no point going far above L */
        if (S < min_size) continue;  /* FFT too small to hold input poly */
        int m = (S >= L) ? 0 : L - S;
        double correction = (double)(m+1) * (m+1) * FMA_NS;
        double cost = calib_times_ns[i] + correction;
        if (cost < best_cost) {
            best_cost = cost;
            *out_size = S;
            *out_wrap_m = m;
        }
    }
}
